import type { Metadata } from "next";
import StationOpsConsole from "./StationOpsConsole";

export const metadata: Metadata = {
  title: "駅務管理コンソール — 新宿駅 | ぐんじょう 鉄道",
  description:
    "駅係員・駅長向けの駅務管理コンソール。新宿駅の自動改札機・券売機・精算機・ICチャージ機・エレベーター/エスカレーター/ホームドアの稼働状態を状態盤で一覧監視し、故障・通信エラー・現金少をスキャン。要対応キューでつり銭補充・機器復旧・警察届出期限をトリアージし、遺失物（拾得物）台帳の返還・警察届出を処理。のりこし精算の不足額早見と当日収受サマリ、つり銭・きっぷ在庫レベルを把握し、当務の引継ぎ・業務日誌を署名で確定する駅事務室向け画面。",
};

export default function StationOpsPage() {
  return <StationOpsConsole />;
}

