export type EquipmentStatus =
  | "稼働"
  | "点検中"
  | "故障"
  | "通信エラー"
  | "現金少";

export type EquipmentKind =
  | "自動改札機"
  | "自動券売機"
  | "自動精算機"
  | "ICチャージ機"
  | "エレベーター"
  | "エスカレーター"
  | "ホームドア";

