  location: string;
  status: EquipmentStatus;
  /** 機番（駅務員が無線で呼ぶ識別子）。 */
  unit: string;
  /** 直近の状態更新。 */
  updatedAt: string; // ISO
  /** 障害・特記事項の一言。 */
  note?: string;
}

