"use client";

import * as React from "react";
import {
  IconCircleCheck,
  IconAlertTriangle,
  IconTool,
  IconWifiOff,
  IconCoin,
  IconBuildingFactory2,
} from "@tabler/icons-react";
import {
  Badge,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Icon,
  Tag,
} from "@gunjo/ui";

import {
  equipment as ALL_EQUIPMENT,
  STATUS_BADGE,
  type Equipment,
  type EquipmentStatus,
} from "./data";

// 状態 → アイコン（色だけに頼らない）。ActionQueue と同じ意味付けに揃える。
const STATUS_ICON: Record<EquipmentStatus, typeof IconCircleCheck> = {
  稼働: IconCircleCheck,
  点検中: IconTool,
  故障: IconAlertTriangle,
  通信エラー: IconWifiOff,
  現金少: IconCoin,
};

const STATUS_ACCENT: Record<EquipmentStatus, string> = {
  稼働: "text-success",
  点検中: "text-info",
  故障: "text-destructive",
  通信エラー: "text-destructive",
  現金少: "text-warning",
};

// 障害が目立つように：故障 → 通信エラー → 現金少 → 点検中 → 稼働 の順。
const STATUS_RANK: Record<EquipmentStatus, number> = {
  故障: 0,
  通信エラー: 1,
  現金少: 2,
  点検中: 3,
  稼働: 4,
};

const isFault = (s: EquipmentStatus) =>
  s === "故障" || s === "通信エラー" || s === "現金少";

function EquipmentTile({ e }: { e: Equipment }) {
  const fault = isFault(e.status);
  const time = e.updatedAt.slice(11, 16);
  return (
    <li
      className={[
        "rounded-lg border p-3 transition-colors",
        fault
          ? "border-destructive-border bg-destructive-subtle"
          : e.status === "点検中"
            ? "border-info-border bg-info-subtle"
            : "border-border bg-card",
      ].join(" ")}
      // 設備1台 = 一つのまとまった読み上げ単位にする
      aria-label={`${e.kind} ${e.unit}（${e.location}）状態 ${e.status}${e.note ? `、${e.note}` : ""}、更新 ${time}`}
    >
      <div className="flex items-start justify-between gap-2">
        <div className="min-w-0">
          <div className="truncate text-sm font-semibold text-foreground">
            {e.unit}
          </div>
          <div className="mt-0.5 text-xs text-muted-foreground">
            {e.location} ・ {e.kind}
          </div>
        </div>
        <Badge
          variant={STATUS_BADGE[e.status]}
          icon={
            <Icon
              icon={STATUS_ICON[e.status]}
              size="sm"
              className={STATUS_ACCENT[e.status]}
              aria-hidden
            />
          }
        >
          {e.status}
        </Badge>
      </div>
      {e.note ? (
        <p
          className={[
            "mt-2 text-xs",
            fault ? "text-destructive-subtle-foreground" : "text-muted-foreground",
          ].join(" ")}
        >
          {e.note}
        </p>
      ) : null}
      <div className="mt-2 flex items-center justify-between">
        <span className="font-mono text-[11px] text-muted-foreground">
          {e.id}
        </span>
        <span className="text-[11px] text-muted-foreground">更新 {time}</span>
      </div>
    </li>
  );
}

export interface EquipmentBoardProps {
  /** 種別フィルタ（"all" で全件）。 */
  kindFilter?: string;
}

/**
 * 駅設備・機器の状態盤。障害（故障 / 通信エラー / 現金少）を先頭に寄せて
 * スキャンしやすくする。@gunjo/ui に「設備状態ボード」コンポーネントが
 * 無いため Card + Badge + Icon で手組み（レポートの評価対象）。
 */
export function EquipmentBoard({ kindFilter = "all" }: EquipmentBoardProps) {
  const list = React.useMemo(() => {
    const filtered =
      kindFilter === "all"
        ? ALL_EQUIPMENT
        : ALL_EQUIPMENT.filter((e) => e.kind === kindFilter);
    return [...filtered].sort(
      (a, b) =>
        STATUS_RANK[a.status] - STATUS_RANK[b.status] ||
        a.location.localeCompare(b.location, "ja"),
    );
  }, [kindFilter]);

  const faultCount = list.filter((e) => isFault(e.status)).length;

  return (
    <Card>
      <CardHeader className="flex-row items-center justify-between gap-2 space-y-0 p-4">
        <CardTitle as="h2" className="flex items-center gap-2 text-base">
          <Icon
            icon={IconBuildingFactory2}
            size="sm"
            className="text-muted-foreground"
            aria-hidden
          />
          設備状態盤
        </CardTitle>
        <div className="flex items-center gap-2">
          {faultCount > 0 ? (
            <Tag variant="destructive" size="sm">
              要対応 {faultCount}
            </Tag>
          ) : (
            <Tag variant="outline" size="sm">
              障害なし
            </Tag>
          )}
          <span className="text-xs text-muted-foreground">{list.length} 台</span>
        </div>
      </CardHeader>
      <CardContent className="p-4 pt-0">
        {list.length === 0 ? (
          <p className="rounded-md border border-dashed px-4 py-6 text-center text-sm text-muted-foreground">
            該当する機器がありません
          </p>
        ) : (
          <ul className="grid grid-cols-1 gap-2 sm:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-4">
            {list.map((e) => (
              <EquipmentTile key={e.id} e={e} />
            ))}
          </ul>
        )}
      </CardContent>
    </Card>
  );
}

