"use client";

import * as React from "react";
import type { ColumnDef } from "@gunjo/ui";
import {
  IconCheck,
  IconBuildingBank,
  IconClockExclamation,
} from "@tabler/icons-react";
import {
  ActionDataTable,
  Badge,
  Icon,
} from "@gunjo/ui";

import {
  lostItems as INITIAL_ITEMS,
  LOST_STATE_BADGE,
  type LostItem,
} from "./data";

function fmtDateTime(iso: string): string {
  // ISO（+09:00）から表示用の "MM/DD HH:mm"。
  return `${iso.slice(5, 7)}/${iso.slice(8, 10)} ${iso.slice(11, 16)}`;
}

function deadlineSoon(iso: string): boolean {
  // 期限まで 24h を切っていれば true（本日 = 2026-06-28 を基準に簡易判定）。
  const ms = new Date(iso).getTime() - new Date("2026-06-28T09:00:00+09:00").getTime();
  return ms <= 24 * 60 * 60 * 1000;
}

export function LostAndFound() {
  const [items, setItems] = React.useState<LostItem[]>(INITIAL_ITEMS);

  const setState = React.useCallback(
    (ids: string[], state: LostItem["state"]) => {
      setItems((prev) =>
        prev.map((it) => (ids.includes(it.id) ? { ...it, state } : it)),
      );
    },
    [],
  );

  const columns = React.useMemo<ColumnDef<LostItem>[]>(
    () => [
      {
        accessorKey: "id",
        header: "受付番号",
        cell: ({ row }) => (
          <span className="font-mono text-xs text-muted-foreground">
            {row.original.id}
          </span>
        ),
      },
      {
        accessorKey: "foundAt",
        header: "拾得日時",
        cell: ({ row }) => (
          <span className="whitespace-nowrap text-sm">
            {fmtDateTime(row.original.foundAt)}
          </span>
        ),
      },
      { accessorKey: "place", header: "拾得場所" },
      {
        accessorKey: "kind",
        header: "種別",
        cell: ({ row }) => <Badge variant="outline">{row.original.kind}</Badge>,
      },
      {
        accessorKey: "feature",
        header: "特徴",
        cell: ({ row }) => (
          <span className="text-sm text-muted-foreground">
            {row.original.feature}
          </span>
        ),
      },
      {
        accessorKey: "state",
        header: "状態",
        cell: ({ row }) => (
          <Badge variant={LOST_STATE_BADGE[row.original.state]}>
            {row.original.state}
          </Badge>
        ),
      },
      {
        accessorKey: "keepUntil",
        header: "保管期限",
        cell: ({ row }) => {
          const soon =
            deadlineSoon(row.original.keepUntil) &&
            row.original.state === "お預かり中";
          return (
            <span
              className={
                soon
                  ? "inline-flex items-center gap-1 whitespace-nowrap text-sm font-semibold text-destructive"
                  : "whitespace-nowrap text-sm text-muted-foreground"
              }
            >
              {soon ? (
                <Icon icon={IconClockExclamation} size="sm" aria-hidden />
              ) : null}
              {fmtDateTime(row.original.keepUntil)}
            </span>
          );
        },
      },
    ],
    [],
  );

  return (
    <ActionDataTable
      columns={columns}
      data={items}
      getRowId={(row) => row.id}
      getRowLabel={(row) => `${row.kind}（${row.id}）`}
      enableSelection
      filter={{ columnId: "place", placeholder: "拾得場所で絞り込み…" }}
      rowActions={[
        {
          id: "return",
          label: "返還処理",
          icon: IconCheck,
          variant: "outline",
          disabled: (row) => row.state !== "お預かり中",
          disabledReason: (row) =>
            row.state === "返還済" ? "返還済み" : "警察届出済みのため不可",
          onSelect: (row) => setState([row.id], "返還済"),
        },
        {
          id: "police",
          label: "警察届出",
          icon: IconBuildingBank,
          variant: "outline",
          disabled: (row) => row.state !== "お預かり中",
          disabledReason: () => "お預かり中のみ届出可",
          onSelect: (row) => setState([row.id], "警察届出"),
        },
      ]}
      rowActionsVariant="menu"
      bulkActions={[
        {
          id: "bulk-police",
          label: "選択を警察届出",
          icon: IconBuildingBank,
          onSelect: (rows) =>
            setState(
              rows.filter((r) => r.state === "お預かり中").map((r) => r.id),
              "警察届出",
            ),
        },
      ]}
    />
  );
}

